/**
 * Row of clickable example snippets shown above the code input card.
 * Clicking a chip pre-fills both the textarea and the language pill.
 */

import React from 'react';
import { EXAMPLES } from '../../examples';

interface Props {
  onPick: (code: string, language: string) => void;
  disabled?: boolean;
}

export const ExamplePicker: React.FC<Props> = ({ onPick, disabled }) => {
  return (
    <div
      className="mx-auto flex w-full max-w-4xl flex-wrap items-center gap-sm px-md md:px-lg pb-md"
      data-testid="example-picker"
    >
      <span className="text-label uppercase tracking-[0.12em] text-ink-muted">
        Try one of these
      </span>
      {EXAMPLES.map((ex) => (
        <button
          key={ex.id}
          onClick={() => onPick(ex.code, ex.language)}
          disabled={disabled}
          className="rounded-pill border border-border-subtle bg-white/[0.03] px-3 py-1.5 text-[12.5px] text-ink-secondary hover:border-accent/50 hover:bg-white/[0.06] hover:text-ink-primary transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
          data-testid={`example-chip-${ex.id}`}
        >
          {ex.label}
        </button>
      ))}
    </div>
  );
};
